    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int x = 0, y = 0;
        int dx = 1, dy = 0;
        int step = 1;
        while (1) {
            for (int i = 0; i < step; i++) {
                if (x == X && y == Y) {
                    printf("YES\n");
                    goto next_test_case;
                }
                x += dx;
                y += dy;
            }
            if (dx == 1) dx = 0, dy = 1;
            else if (dy == 1) dx = -1, dy = 0;
            else if (dx == -1) dx = 0, dy = -1;
            else dx = 1, dy = 0;
            step++;
            if (x > X && y > Y || x < X && y < Y || x > X && y < Y || x < X && y > Y) break;
        }
        printf("NO\n");
        next_test_case:;
    }
    return 0;
}

