code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt(), Y = sc.nextInt();
            int x = 0, y = 0;
            int dx = 1, dy = 0;
            int step = 1;
            while (true) {
                for (int i = 0; i < step; i++) {
                    if (x == X && y == Y) {
                        System.out.println("YES");
                        break;
                    }
                    x += dx;
                    y += dy;
                }
                if (dx == 1) dx = 0; dy = 1;
                else if (dy == 1) dx = -1; dy = 0;
                else if (dx == -1) dx = 0; dy = -1;
                else dx = 1; dy = 0;
                step++;
                if (x > X && y > Y || x < X && y < Y || x > X && y < Y || x < X && y > Y) break;
            }
            if (x != X || y != Y) System.out.println("NO");
        }
    }
}

